import { ImageStyle, StyleProp, ImageSourcePropType } from 'react-native';

import { IconSet } from 'react-native-icomoon';

import {
  PropsShadowTokens,
  PropsSpacesHorizontal,
  PropsSpacesVertical,
} from '../../../../styles/Models';
import { PropsTokenColorsCore } from '../../../../styles/Models/type.colors';
import {
  PropsIconsNameCore,
  PropsSizeIconCore,
} from '../../../../styles/Models/type.icon';
import { PropsPaddingCore } from '../../../../styles/Models/type.padding';

export interface PropsIcon {
  size?: PropsSizeIconCore;
  name?: PropsIconsNameCore;
  style?: StyleProp<ImageStyle> | undefined;
  color?: PropsTokenColorsCore;
  onPress?: () => void;
  iconSet?: IconSet;
  testID?: string;
  disabled?: boolean;
  mt?: PropsSpacesHorizontal;
  ml?: PropsSpacesVertical;
  mb?: PropsSpacesHorizontal;
  mr?: PropsSpacesVertical;
  hasBackground?: boolean;
  backgroundType?: 'square' | 'circle';
  bgColor?: PropsTokenColorsCore;
  bgColorCircle?: PropsTokenColorsCore;
  borderColor?: PropsTokenColorsCore;
  hasStroke?: boolean;
  shadow?: PropsShadowTokens;
  hasBackgroundCircle?: boolean;
  hasBackgroundSvg?: boolean;
}

export interface PropsIconView extends PropsIcon {
  isImage: boolean;
  showBackground?: boolean;
  showBackgroundCircle?: boolean;
  verifyIcon: () => boolean;
  sourceImage: () => ImageSourcePropType;
  bgPadding: () => PropsPaddingCore;
  bgPaddingCircle: () => PropsPaddingCore;
  renderBgColor: () => PropsTokenColorsCore | undefined;
}

export interface propsItem {
  properties: {
    name: string;
  };
}

