import { Dispatch, SetStateAction } from 'react';

import {
  PropsSpacesVertical,
  PropsSpacesHorizontal,
} from '../../../../styles/Models';
import { PropsTokenColorsCore } from '../../../../styles/Models/type.colors';
import {
  PropsIconsNameCore,
  PropsSizeIconCore,
} from '../../../../styles/Models/type.icon';
import { PropsTokensTextCore } from '../../../../styles/Models/type.text';

import { typeSkeleton } from '../../../atoms/Skeleton/Models';

export type TextIconType =
  | 'default'
  | 'information'
  | 'list'
  | 'price'
  | 'label'
  | 'highlight';
export interface PropsTextIcon {
  iconName?: PropsIconsNameCore;
  description?: string;
  descriptionInfo?: string;
  descriptionInfoColor?: PropsTokenColorsCore;
  numberOfLinesDescriptionInfo?: number;
  iconColor?: PropsTokenColorsCore;
  bgIconColor?: PropsTokenColorsCore;
  textColor?: PropsTokenColorsCore;
  type?: TextIconType;
  tagLabelText?: string;
  tagLabelType?: string;
  tagLabelHighlight?: boolean;
  tagLabelIcon?: PropsIconsNameCore;
  iconLabelColorRight?: PropsTokenColorsCore;
  priceValue?: string;
  priceValueColor?: PropsTokenColorsCore;
  disabled?: boolean;
  onPress?: () => void;
  numberOfLinesDescription?: number;
  isLoading?: boolean;
  loadingType?: typeSkeleton;
  hideSeparator?: boolean;
  hasBackgroundIcon?: boolean;
  hideValue?: boolean;
  bulletColor?: PropsTokenColorsCore;
  mt?: PropsSpacesHorizontal;
  ml?: PropsSpacesVertical;
  mb?: PropsSpacesHorizontal;
  mr?: PropsSpacesVertical;
  testID?: string;
}

export interface PropsTextIconView extends PropsTextIcon {
  textColorSet: () => PropsTokenColorsCore;
  textTypeSet: () => PropsTokensTextCore;
  iconSizeSet: () => PropsSizeIconCore;
  skeletonWidth: number;
  setSkeletonWidth: Dispatch<SetStateAction<number>>;
  hasBackgroundIconSet: () => PropsTokenColorsCore;
}

export interface ViewSizeType {
  width: number;
}

